import type { PointsConfig } from '@smartcart/shared-types';
import type { SessionItem } from '../entities/shopping-session.entity';
import type { IPointsCalculationStrategy } from './points-calculation-strategy.interface';

/**
 * VOLUME_TIER — `quantity * tier.pointsPerUnit` for the tier whose
 * [minQty, maxQty] range contains the quantity (README §2.3 Strategy Types).
 */
export class VolumeTierStrategy implements IPointsCalculationStrategy {
  readonly strategyType = 'VOLUME_TIER' as const;

  calculate(item: SessionItem, config: PointsConfig): number {
    if (config.type !== 'VOLUME_TIER') {
      throw new Error('VolumeTierStrategy received a non-VOLUME_TIER config');
    }
    const tier = config.tiers.find(
      (t) => item.quantity >= t.minQty && item.quantity <= t.maxQty,
    );
    // Quantity outside every configured tier earns nothing for this line.
    if (!tier) return 0;
    return item.quantity * tier.pointsPerUnit;
  }
}
